import React, {
  useState,
  useEffect,
  useMemo,
  useRef,
  useCallback,
} from "react";
import GrComboBox from "./GridComponents/GrComboBox";
import GrFile from "./GridComponents/GrFile";
import GrMultilineBox from "./GridComponents/GrMultilineBox";
import GrNumericBox from "./GridComponents/GrNumericBox";
import GrButton from "./GridComponents/GrButton";
import GrHeader from "./GridComponents/GrHeader";
import GrModal from "./GridComponents/GrModal";
import GrDateBox from "./GridComponents/GrDateBox";
import { AgGridReact } from "ag-grid-react";
import "ag-grid-community/styles/ag-grid.css";
import "ag-grid-community/styles/ag-theme-alpine.css";
import GrGrid from "./GridComponents/GrGrid";
import gridcoldefs from "./gridcoldefs.json";
import PopupForm from "./PopupForm";
import { useContext } from "react";
import { FormContext } from "../Contexts/FormContext";

const Grid = (defs) => {

  debugger;
  console.log(defs)

  const {setStageGridRefs , stageGridRefs } = useContext(FormContext);

  stageGridRefs[defs.fieldname] = useRef();
  const gridRef = useRef();
  const [modaldata, setModalData] = useState(null);

  let ChildGridElements = []

  let modaldefs = null;

  const [rowData, setRowData] = useState(defs.coldef.val == "" ? [] : defs.coldef.val );

  /* Load Custom components based on column control type */
  const gridComponents = {
    2: GrNumericBox,
    3: GrComboBox,
    4: GrDateBox,
    9: GrFile,
    12: "agLargeTextCellEditor",
    13: GrButton,
    14: GrModal
  };

  const colDef = [];

  // supporting reference data
  const carMappings = [
    {
      k: "tyt",
      v: "Toyota",
    },
    {
      k: "frd",
      v: "Ford",
    },
    { k: "prs", v: "Porsche" },
    { k: "nss", v: "Nissan" },
  ];

  function lookupValue(mappings, key) {
    let obj = mappings.find((o) => o.k === key);

    return !obj ? "" : obj.v;
  }

  function lookupKey(mappings, key) {
    let obj = mappings.find((o) => o.k === key);
    return !obj ? "" : obj.k;
  }
  // convert code to value
  function makeValueFormatter(params) {
    /* if(lookupValue(carMappings, params.value) ==""){
     
           var rowNode = gridRef.current.api.getRowNode(params.data.id);
           rowNode.setDataValue(params.colDef.field, ""newPrice"");
     
         } */
    return lookupValue(carMappings, params.value);
  }

  // convert value to code
  function makeValueParser(params) {
    return lookupKey(carMappings, params.value);
  }

  function clicked(field) {
    setModalData(field);
  }

  function uuidv4() {
    return ([1e7]+-1e3+-4e3+-8e3+-1e11).replace(/[018]/g, c =>
      (c ^ crypto.getRandomValues(new Uint8Array(1))[0] & 15 >> c / 4).toString(16)
    );
  }

  for (const field in defs.coldef.child) {

    const element = defs.cntrlsdata[field]

    if (element.ty == "10" && defs.fieldname) {

      element.child = {}
      element.child[field] = {}
      element.fieldname = field
      element.parentfieldanme = defs.fieldname
      ChildGridElements.push(element)
      //ChildGridElements.push(defs.stagelementdata.elms[defs.fieldname].child[field])

    }


    colDef.push({
      field: field,
      headerName: element.cap,
      ...(element.editor &&
        !element.internal && {
        cellEditor: gridComponents[element.ty],
      }),
      ...(element.renderer && {editable: false}),
      ...(!element.renderer && {editable: element.editable}),
      ...(element.ty == "3" && {
        cellEditorParams: { values: carMappings },
        valueFormatter: eval(element.valueFormatter),
        valueParser: eval(element.valueParser),
      }),
      ...((element.editor &&
        element.internal) && {
        cellEditor: element.ty,
        cellEditorPopup: element.cellEditorPopup,
      }),
      ...(element.renderer || element.ty == "10" && {
        cellRenderer: gridComponents[element.ty == "10" ? "14" : element.ty],
        cellRendererParams: {
          fieldname: field, cap: element.cap, defs, elementdefs: defs.cntrlsdata, stagelementdata: defs.stagelementdata
        }
      }),

      ...(element.renderer && element.ty != "10" && {
        cellRenderer: gridComponents[element.ty],
        ...(element.cellRendererParams && {
          cellRendererParams: {
            clicked: eval(element.cellRendererParams.clicked),
            fieldname: field, cap: element.cap, defs, elementdefs: defs.cntrlsdata, stagelementdata: defs.stagelementdata
          }
        }),

      })

    });


  }

  /*  defs.coldef.child.forEach((element) => {
  
      colDef.push({
        field: element.field,
        headerName : element.cap,
        ...(element.editor &&
          !element.internal && {
            cellEditor: gridComponents[element.cellEditor],
          }),
        editable: element.editable,
        ...(element.cellEditor == "grCombobox" && {
          cellEditorParams: { values: carMappings },
          valueFormatter: eval(element.valueFormatter),
          valueParser: eval(element.valueParser),
        }),
        ...((element.editor &&
          element.internal) && {
            cellEditor: element.cellEditor,
            cellEditorPopup: element.cellEditorPopup,
          }),
        ...(element.renderer && {
          cellRenderer: gridComponents[element.cellEditor],
        }),
        ...(element.cellRendererParams && {
          cellRendererParams: {clicked : eval(element.cellRendererParams.clicked) } 
        }),
      });
    }); */


  //const [columnDefs, setColumndefs] = useState(colDef);

  const columnDefs = colDef;

  /*const [columnDefs, setColumndefs] = useState([
    { headerName: "Row ID", valueGetter: "node.id"  },
    {
      field: "Institution",
      cellEditor: gridComponents["grCombobox"],
      editable: true,
      cellEditorParams: { values: carMappings },
      valueFormatter: makeValueFormatter,
      valueParser: makeValueParser,
    },
    { field: "LoanRef", headerName: "Loan No", editable: true },
    { field: "LoanAmount", editable: true, cellEditor: GrNumericBox  },
    { field: "EMI", editable: true, cellEditor: GrNumericBox },
    { field: "LoanDate", editable: true, cellEditor: GrDateBox },
    {
      field: "LoanDetails",
      editable: true,
      cellEditor: "agLargeTextCellEditor",
      cellEditorPopup: true,
    },
    { field: "LoanDocument", cellRenderer: GrFile },
    {
      field: "ScheduleDetails",
      cellRenderer: GrModal,
      cellRendererParams: {
        clicked: clicked,
      },
    },
  ]); */

  function createNewRowData() {
    debugger;
    const newData = {
      _rid:uuidv4()  
    }
    return newData;
  }

  const addItems = useCallback((addIndex) => {

    const res = stageGridRefs[defs.fieldname].current.api.applyTransaction({
      add: [createNewRowData()],
      addIndex: addIndex,
    });
  }, []);

  const onRemoveSelected = useCallback(() => {

    const selectedData = stageGridRefs[defs.fieldname].current.api.getSelectedRows();
    const res = stageGridRefs[defs.fieldname].current.api.applyTransaction({ remove: selectedData });
  }, []);

  const defaultcoldefs = useMemo(
    () => ({
      flex:2,
      singleClickEdit : true , 
      editable : false,
      alwaysShowHorizontalScroll : true,
      resizable : true,
      
     
    }),
    []
  );

  const getRowId = useMemo(() => {
    return (params) => params.data._rid;
  }, []);


  return (
    <>
      <div className="row g-0">
        <GrHeader
          add={addItems}
          remove={onRemoveSelected}
          header={defs.coldef.cap}
          mbtn={defs.coldef.mbtn}
        ></GrHeader>

        <div className="ag-theme-alpine" >
          <AgGridReact
            ref={stageGridRefs[defs.fieldname] }
            rowData={rowData}
            columnDefs={columnDefs}
            defaultColDef={defaultcoldefs}
            domLayout={'autoHeight'}
            stopEditingWhenCellsLoseFocus 
            rowSelection= {"single"}
            getRowId={getRowId}
            pagination
            
          
           
          ></AgGridReact>
        </div>

        {ChildGridElements.length>0 && ChildGridElements.map((item) => (


          <PopupForm eid={""} fieldname={item.fieldname} cap={item.cap} col={item.col} mn={item.mn} val={item.val} mxLen={item.mxLen} ev="undefined" defs={item} elementdefs={defs.cntrlsdata} stagelementdata={defs.stagelementdata} parentfieldanme={defs.fieldname} />


        ))}
      </div>
    </>
  );
};

export default Grid;
