import React, { useContext } from "react";
import { FormContext } from "../Contexts/FormContext";
import { EventCaller } from "../BusinessLogics/EventHandler";
import { compressBase64 } from "../../utilities/utils";

const ComboBox = ({ eid, fieldname, cap, col, mn, ev, val, cod }) => {
  const { register, getValues, setValue, combodata, setComboData, elements } =
    useContext(FormContext);

  const options = combodata[cod] ? combodata[cod] : [];

  let clientevent ={}

  if (ev) {
    clientevent = JSON.parse(ev.change);
  }

  return (
    <div className={`${col} mb-3`}>
      <label
        htmlFor={fieldname}
        className={`${mn ? "required" : ""} form-label`}
      >
        {cap}
      </label>
      <select
        className="form-select"
        aria-label="Default select example"
        {...register(fieldname, {
          required: mn,
          value: val,
          onChange: () =>
            ev
              ? EventCaller(
                clientevent.fn,
                  fieldname,
                  clientevent.outel,
                  getValues,
                  combodata,
                  setComboData,
                  elements
                )
              : "",
        })}
      >
          <option key="0" value="">
            --Select--
          </option>
        {
        
        options.map((item) => (
          <option key={item.k} value={item.k}>
            {item.v}
          </option>
        ))}
      </select>
    </div>
  );
};

export default ComboBox;
